function setupReactivity(client: NuxtDevtoolsHostClient, router: Router | undefined, timeMetric: TimelineMetrics) {
  const refreshReactivity = debounce(() => {
    client.hooks.callHook('host:update:reactivity')
  }, 100, { trailing: true })

  // trigger update for reactivity
  watch(() => [
    client.nuxt.payload,
    client.app.colorMode.value,
    client.metrics.loading(),
    timeMetric,
  ], () => {
    refreshReactivity()
  }, { deep: true })

  // trigger update for route change
  router?.afterEach(() => {
    refreshReactivity()
  })
  // trigger update for app mounted
  client.nuxt.hook('app:mounted', () => {
    refreshReactivity()
  })
  // record last route
  client.hooks.hook('devtools:navigate', (path) => {
    state.value.route = path
  })
}

addBuildPlugin(FontFamilyInjectionPlugin({
  dev: nuxt.options.dev,
  fontsToPreload: fontMap,
  processCSSVariables: options.experimental?.processCSSVariables ?? options.processCSSVariables,
  shouldPreload(fontFamily, fontFace) {
    const override = options.families?.find(f => f.name === fontFamily)
    if (override && override.preload !== undefined) {
      return override.preload
    }
    if (options.defaults?.preload !== undefined) {
      return options.defaults.preload
    }
    return fontFace.src.some(s => 'url' in s) && !fontFace.unicodeRange
  },
  async resolveFontFace(fontFamily, fallbackOptions) {
    const override = options.families?.find(f => f.name === fontFamily)

    // This CSS will be injected in a separate location
    if (override?.global) {
      return
    }

    resolveFontFaceWithOverride ||= await resolvePromise
    return resolveFontFaceWithOverride(fontFamily, override, fallbackOptions)
  },
}))

export const postHandler = defineEventHandler(async (event) => {
  const body = await readBody<Omit<HydrationMismatchPayload, 'id'>>(event)
  assertPayload(body)
  const payload: HydrationMismatchPayload = {
    id: crypto.randomUUID(),
    htmlPreHydration: body.htmlPreHydration,
    htmlPostHydration: body.htmlPostHydration,
    componentName: body.componentName,
    fileLocation: body.fileLocation,
  }
  hydrationMismatches.push(payload)
  if (hydrationMismatches.length > 20) {
    const evicted = hydrationMismatches.shift()
    if (evicted) {
      getRPC()?.onHydrationCleared([evicted.id])
    }
  }
  getRPC()?.onHydrationMismatch(payload)
  setResponseStatus(event, 201)
  return payload
})

nuxt.hook('builder:watch', async (event, path) => {
  const resolvedPath = await nuxtResolvePath(path)

  if (ctx.scanner) {
    ctx.scanner.extractFromCode(
      await fs.readFile(resolvedPath, 'utf-8').catch(() => ''),
      ctx.scannedIcons,
    )
  }

  if (collectionDirs.some(cd => resolvedPath.startsWith(cd))) {
    await ctx.loadCustomCollection(true) // Force re-read icons from fs

    // Update client and server bundles
    await updateTemplates({
      filter: template => template.filename.startsWith('nuxt-icon-'),
    })

    if (viteDevServer) {
      // Invalidate client bundle in vite dev server cache
      const nuxtIconClientBundleModule = await viteDevServer.moduleGraph.getModuleByUrl('/.nuxt/nuxt-icon-client-bundle.mjs')
      if (nuxtIconClientBundleModule) {
        viteDevServer.moduleGraph.invalidateModule(nuxtIconClientBundleModule)
        await viteDevServer.reloadModule(nuxtIconClientBundleModule)
      }
    }
  }
})

const uploadHandler = async (event: H3Event) => {
  const { pathname } = await getValidatedRouterParams(event, z.object({
    pathname: z.string().min(1)
  }).parse)

  const { uploadId, partNumber } = await getValidatedQuery(event, z.object({
    uploadId: z.string(),
    partNumber: z.coerce.number()
  }).parse)

  const contentLength = Number(getHeader(event, 'content-length') || '0')

  const stream = getRequestWebStream(event)!
  const body = await streamToArrayBuffer(stream, contentLength)

  const mpu = await blob.resumeMultipartUpload(pathname, uploadId)

  try {
    return await mpu.uploadPart(partNumber, body)
  } catch (e: any) {
    throw createError({ status: 400, message: e.message })
  }
}

nitroApp.hooks.hook('render:response', (response, { event }) => {
  const rules = resolveSecurityRules(event)
  if (rules.enabled && rules.headers) {
    const headers = rules.headers

    Object.entries(headers).forEach(([header, value]) => {
      const headerName: HeaderName = header === 'contentSecurityPolicy' && rules.contentSecurityPolicyReportOnly
        ? 'Content-Security-Policy-Report-Only'
        : getNameFromKey(header as OptionKey)

      if (value === false) {
        const { headers: standardHeaders } = getRouteRules(event)
        const standardHeaderValue = standardHeaders?.[headerName]
        const currentHeaderValue = getResponseHeader(event, headerName)
        if (standardHeaderValue === currentHeaderValue) {
          removeResponseHeader(event, headerName)
        }
      } else {
        const headerValue = headerStringFromObject(header as OptionKey, value)
        setResponseHeader(event, headerName, headerValue)
      }
    })
  }
})

addTemplate({
  filename: 'types/supabase-database.d.ts',
  getContents: async () => {
    if (options.types) {
      try {
        // resolvePath is used to minify user input error.
        const path = await resolvePath(options.types)
        const typesPath = await resolvePath('~~/.nuxt/types/') // this is the default path for nuxt types

        if (fs.existsSync(path)) {
          // Make the path relative to the "types" directory.
          return `export * from '${relative(typesPath, path)}'`
        }
        else {
          logger.warn(
            `Database types configured at "${options.types}" but file not found at "${path}". `
            + `Using "Database = unknown".`,
          )
        }
      }
      catch (error) {
        logger.error(`Failed to load Supabase database types from "${options.types}":`, error)
      }
    }

    return `export type Database = unknown`
  },
})

if (options.fingerprint && import.meta.client) {
  // Skip if server already detected a bot
  if (!botContext.value?.isBot) {
    runFingerprinting().then(([result, error]) => {
      if (error) {
        options?.onFingerprintError?.(error)
      }
      else {
        // Update context with fingerprinting result
        if (result) {
          botContext.value = result
        }
        else {
          // No bot detected, update context to reflect fingerprinting ran
          botContext.value = {
            isBot: false,
            trusted: false,
          }
        }
        // Call the result callback with the final context
        options?.onFingerprintResult?.(botContext.value)
      }
    })
  }
}

