export function handleNonce(event: H3Event) {
  const query = getQuery<{ code?: string }>(event)
  // If the code is in the query, get the nonce from the cookie and delete the cookie
  if (query.code) {
    const nonce = getCookie(event, 'nuxt-auth-nonce')
    deleteCookie(event, 'nuxt-auth-nonce')
    return nonce
  }

  // If the code is not in the query, generate a new nonce and set it in the cookie
  const nonce = encodeBase64Url(getRandomBytes(8))
  setCookie(event, 'nuxt-auth-nonce', nonce, {
    httpOnly: true,
    secure: !isDevelopment,
    sameSite: 'lax',
    maxAge: OAUTH_COOKIE_MAX_AGE,
    path: '/',
  })
  return nonce
}

export function initTimelineMetrics(): TimelineMetrics {
  if (import.meta.server)
    return undefined!

  if (window.__NUXT_DEVTOOLS_TIMELINE_METRICS__)
    return window.__NUXT_DEVTOOLS_TIMELINE_METRICS__

  Object.defineProperty(window, '__NUXT_DEVTOOLS_TIMELINE_METRICS__', {
    value: reactive(
      window.__NUXT_DEVTOOLS_TIMELINE_METRICS__ || {
        events: [],
        nonLiteralSymbol,
        // TODO: sync with server config
        options: useObjectStorage('nuxt-devtools-timeline-metrics-options', {
          enabled: false,
          stacktrace: true,
          arguments: true,
        }),
      },
    ),
    enumerable: false,
    configurable: true,
  })

  return window.__NUXT_DEVTOOLS_TIMELINE_METRICS__!
}

function setCookieDeduped(event: H3Event, name: string, value: string, serializeOptions: CookieSerializeOptions) {
  // Deduplicate by removing the same name cookie
  let setCookiesHeader = getResponseHeader(event, 'set-cookie')
  if (setCookiesHeader) {
    if (!Array.isArray(setCookiesHeader)) {
      setCookiesHeader = [setCookiesHeader.toString()]
    }

    // Safety: `cookie-es` builds up the cookie by using `name + '=' + encodedValue`
    // https://github.com/unjs/cookie-es/blob/a3495860248b98e7015c9a3ade8c6c47ad3403df/src/index.ts#L102
    const filterBy = `${name}=`
    setCookiesHeader = setCookiesHeader.filter(cookie => !cookie.startsWith(filterBy))

    setResponseHeader(event, 'set-cookie', setCookiesHeader)
  }

  setCookie(event, name, value, serializeOptions)
}

return async (log, headers, path?) => {
  if (path && !shouldResolve(path, options)) return false

  const start = Date.now()
  try {
    const session = await auth.api.getSession({ headers: toHeaders(headers) })
    const resolvedIn = Date.now() - start

    if (session) {
      const identified = identifyUser(log, session, options)
      if (identified) {
        log.set({ auth: { resolvedIn, identified: true } } as Record<string, unknown>)
        if (options?.onIdentify) await options.onIdentify(log, session)
        return true
      }
    }

    log.set({ auth: { resolvedIn, identified: false } } as Record<string, unknown>)
    if (options?.onAnonymous) await options.onAnonymous(log)
    return false
  } catch (err) {
    const resolvedIn = Date.now() - start
    log.set({ auth: { resolvedIn, identified: false, error: true } } as Record<string, unknown>)
    if (isDev) console.warn('[evlog/better-auth] Session resolution failed:', err)
    if (options?.onAnonymous) await options.onAnonymous(log)
    return false
  }
}

export const mergeConfigLocales = (configs: LocaleConfig[]) => {
  const merged: Map<string, LocaleObject> = new Map()
  for (const config of configs) {
    for (const locale of config.locales ?? []) {
      const current: LocaleObject = isString(locale) ? { code: locale, language: locale } : assign({}, locale)

      const files = isString(locale) ? [] : resolveRelativeLocales(current, config)
      delete current.file
      delete current.files

      const existing = merged.get(current.code) ?? {
        code: current.code,
        language: current.language,
        files: [] as LocaleFile[],
      }

      existing.files = [...files, ...(existing.files as LocaleFile[])]

      merged.set(current.code, assign({}, current, existing))
    }
  }

  return Array.from(merged.values())
}

const results = await Promise.all(
  filtered.map(async ({ font: f, src: initialSrc, isStaticFallback }) => {
    let src = initialSrc
    let data = await loadFont(event, f, src)
    // Fall back to primary src if the static alternative fails to load (e.g. 404)
    if (!data && src !== f.src && options.supportedFormats.has(fontFormat(f.src))) {
      data = await loadFont(event, f, f.src)
      if (data) {
        src = f.src
        isStaticFallback = false
      }
    }
    if (!data)
      return null
    // Reflect the src actually loaded so downstream dedupe (takumi) keys on the real binary.
    // Drop unicodeRange when using the full static fallback — the subset range doesn't apply
    // to the static TTF, and takumi's subset-chain logic would otherwise split the family.
    return {
      ...f,
      src,
      ...(isStaticFallback ? { unicodeRange: undefined } : {}),
      cacheKey: `${f.family}-${f.weight}-${f.style}-${src}`,
      data,
    } satisfies RuntimeFontConfig
  }),
)

const initialTimeout = setTimeout(() => {
    // work the queue step by step await the promise from each task, delay 1s after each task ends
    const next = async () => {
      if (queue.length === 0) {
        // Clear timeout references when done
        timeoutIds.length = 0
        return
      }

      try {
        await queue.shift()!()
      }
      catch (error) {
        console.error('[sitemap:warm-up] Error warming up sitemap:', error)
      }

      // Only schedule next if we have more items
      if (queue.length > 0) {
        const nextTimeout = setTimeout(next, 1000) // arbitrary delay to avoid throttling
        timeoutIds.push(nextTimeout)
      }
    }
    next()
  }, 2500 /* https://github.com/unjs/nitro/pull/1906 */)

const isRangeSelected = (range: { days?: number, months?: number, years?: number }) => {
  if (!selected.value.start || !selected.value.end) return false

  const currentDate = today(getLocalTimeZone())
  let startDate = currentDate.copy()

  if (range.days) {
    startDate = startDate.subtract({ days: range.days })
  } else if (range.months) {
    startDate = startDate.subtract({ months: range.months })
  } else if (range.years) {
    startDate = startDate.subtract({ years: range.years })
  }

  const selectedStart = toCalendarDate(selected.value.start)
  const selectedEnd = toCalendarDate(selected.value.end)

  return selectedStart.compare(startDate) === 0 && selectedEnd.compare(currentDate) === 0
}

if (typeof rawTimestamp === 'number') {
  const minTimestamp = new Date('2000-01-01').getTime()
  const maxTimestamp = Date.now() + 24 * 60 * 60 * 1000 // 1 day in the future
  if (rawTimestamp < minTimestamp || rawTimestamp > maxTimestamp) {
    throw createError({ statusCode: 400, message: 'Invalid timestamp: value out of reasonable range' })
  }
  timestamp = new Date(rawTimestamp).toISOString()
} else if (typeof rawTimestamp === 'string') {
  if (!isValidISOTimestamp(rawTimestamp)) {
    throw createError({ statusCode: 400, message: 'Invalid timestamp: must be a valid ISO 8601 datetime string' })
  }
  timestamp = rawTimestamp
} else {
  throw createError({ statusCode: 400, message: 'Invalid timestamp: must be string or number' })
}

