const handle: THandler['handle'] = async (request, callOptions) => {
  const { skipped, finish, finishResponse, runWith, logger } = integration.start({ request }, options)

  const initialContext = (callOptions as { context?: Record<string, unknown> } | undefined)?.context ?? {}
  const finalOptions = {
    ...callOptions,
    context: { ...initialContext, log: logger },
  } as Parameters<THandler['handle']>[1]

  if (skipped) {
    return handler.handle(request, finalOptions)
  }

  try {
    const result = await runWith(() => handler.handle(request, finalOptions))
    if (result.matched) {
      result.response = await finishResponse(result.response, { status: result.response.status })
    } else {
      await finish({ status: 404 })
    }
    return result
  } catch (error) {
    await finish({ error: error as Error })
    throw error
  }
}

export function defineNuxtModule<TOptions extends ModuleOptions> (
  definition: ModuleDefinition<TOptions, Partial<TOptions>, false> | NuxtModule<TOptions, Partial<TOptions>, false>,
): NuxtModule<TOptions, TOptions, false>

export function defineNuxtModule<TOptions extends ModuleOptions> (): {
  with: <TOptionsDefaults extends Partial<TOptions>> (
    definition: ModuleDefinition<TOptions, TOptionsDefaults, true> | NuxtModule<TOptions, TOptionsDefaults, true>,
  ) => NuxtModule<TOptions, TOptionsDefaults, true>
}

export function defineNuxtModule<TOptions extends ModuleOptions> (
  definition?: ModuleDefinition<TOptions, Partial<TOptions>, false> | NuxtModule<TOptions, Partial<TOptions>, false>,
) {
  if (definition) {
    return _defineNuxtModule(definition)
  }

  return {
    with: <TOptionsDefaults extends Partial<TOptions>>(
      definition: ModuleDefinition<TOptions, TOptionsDefaults, true> | NuxtModule<TOptions, TOptionsDefaults, true>,
    ) => _defineNuxtModule(definition),
  }
}

const shapes = computed(() => {
  // @ts-expect-error ignore {} not assignable to object
  const val: { [key in keyof T]: Shape } = {}

  if (!props.schema)
    return
  const shape = getBaseSchema(props.schema)?.shape
  if (!shape)
    return
  Object.keys(shape).forEach((name) => {
    const item = shape[name] as ZodAny
    const baseItem = getBaseSchema(item) as ZodAny
    let options = (baseItem && 'values' in baseItem._def) ? baseItem._def.values as string[] : undefined
    if (!Array.isArray(options) && typeof options === 'object')
      options = Object.values(options)

    val[name as keyof T] = {
      type: getBaseType(item),
      default: getDefaultValueInZodStack(item),
      options,
      required: !['ZodOptional', 'ZodNullable'].includes(item._def.typeName),
      schema: item,
    }
  })
  return val
})

return (ctx) => {
  queue = queue.then(async () => {
    const a = ctx.event.audit as AuditFields | undefined
    if (a) {
      if (!initialised && state) {
        inMemoryPrev = (await state.load()) ?? null
        initialised = true
      }
      const prevHash = inMemoryPrev ?? undefined
      const payload = stableStringify({ ...stripIntegrity(ctx.event), audit: { ...stripIntegrity(ctx.event).audit, prevHash } })
      const hash = await digestHex(algorithm, payload)
      ctx.event.audit = { ...a, prevHash, hash }
      inMemoryPrev = hash
      await state?.save(hash)
    }
    await drain(ctx)
  }).catch((err) => {
    console.error('[evlog/audit] signed drain failed:', err)
  })
  return queue
}

