for (const queryFile of queriesFiles) {
  const sqlQuery = await queriesStorage.getItem<string>(queryFile.filename)
  if (!sqlQuery) continue
  const queries = splitSqlQueries(sqlQuery)
  const drizzleOrmPkg = 'drizzle-orm'
  const sql = await import(drizzleOrmPkg).then(m => m.sql)
  try {
    log.debug(`Applying database query \`${getRelativePath(join(hub.dir!, 'db/queries', queryFile.filename))}\`...`)
    for (const query of queries) {
      await db[execute](sql.raw(query))
    }
  } catch (error: any) {
    const message = error.cause?.message || error.message
    log.error(`Failed to apply query \`${getRelativePath(join(hub.dir!, 'db/queries', queryFile.filename))}\`\n${message}`)
    return false
  }

  !import.meta.dev && log.success(`Database query \`${getRelativePath(join(hub.dir!, 'db/queries', queryFile.filename))}\` applied`)
}

this.Compiler = (tree: Root) => {
  const body = compileToJSON(tree)

  let excerpt = undefined
  const excerptIndex = tree.children.findIndex(node => node.type === 'comment' && node.value?.trim() === 'more')
  if (excerptIndex !== -1) {
    excerpt = compileToJSON({
      type: 'root',
      children: tree.children.slice(0, excerptIndex),
    })

    // Include styles if excerpt contains code block
    if (excerpt.children.find(node => node.type === 'element' && node.tag === 'pre')) {
      const lastChild = body.children[body.children.length - 1]
      if (lastChild && lastChild.type === 'element' && lastChild.tag === 'style') {
        excerpt.children.push(lastChild)
      }
    }
  }

  // Top level text nodes are not allowed
  body.children = (body.children || []).filter(child => child.type !== 'text')

  return {
    body,
    excerpt,
  }
}

if (migrationCheck.usedCommunityTemplates.length > 0) {
  p.log.warn('Community templates detected that must be ejected for production:')
  for (const name of migrationCheck.usedCommunityTemplates) {
    p.log.warn(`  • ${name}`)
  }
  if (!dryRun) {
    const shouldEject = skipConfirm || await p.confirm({
      message: 'Eject community templates now?',
      initialValue: true,
    }).then(v => !p.isCancel(v) && v)

    if (shouldEject) {
      const targetDir = existsSync(join(cwd, 'app')) ? join(cwd, 'app') : cwd
      for (const name of migrationCheck.usedCommunityTemplates) {
        ejectTemplate(name, targetDir)
      }
    }
    else {
      p.log.info('Run manually before building for production:')
      for (const name of migrationCheck.usedCommunityTemplates) {
        p.log.info(`  npx nuxt-og-image eject ${name}`)
      }
    }
  }
